"""
mkt-context: Amos ch6-9 — historical/ANE background commentary.
Run: python3 scripts/zc-context-amos-6-9.py

Historical context:
  - Amos prophesied c. 760-750 BCE during Jeroboam II's reign (793-753 BCE),
    Israel's last period of prosperity and territorial expansion before Assyrian crisis.
  - Ch6: the luxury oracle against Samaria's elite; ivory beds (confirmed by
    archaeology at Samaria); the reversal of 'first among nations'.
  - Ch7-8: the five visions (locusts, fire, plumb line, summer fruit, altar);
    the Amaziah confrontation (7:10-17) — prophetic independence from royal cult.
  - Amos 7:14: 'I was no prophet' — explicit rejection of professional prophetic guild.
  - Ch9:7: the radical universalism — YHWH governs Philistine and Syrian migrations too.
  - Ch9:11: the 'booth of David' restoration prophecy quoted in Acts 15:16-17.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "6": {
    "1": "<p>'Woe to those who are at ease in Zion, and to those who feel secure on the mountain of Samaria, the notable men of the first of the nations, to whom the house of Israel comes!' The oracle opens with the dual address to Jerusalem (Zion) and Samaria — both kingdoms simultaneously indicted. The 'notable men of the first of the nations' (<em>nequvei reshit hagoyim</em>) reflects the self-understanding of the Israelite elite during Jeroboam II's reign: Israel had extended its borders from Lebo-hamath to the Sea of the Arabah (2 Kings 14:25), and the ruling class believed this territorial success confirmed their status. The phrase 'to whom the house of Israel comes' — clients coming to patronize the powerful — captures the court culture of the period.</p>",
    "2": "<p>'Pass over to Calneh, and see, and from there go to Hamath the great; then go down to Gath of the Philistines. Are you better than these kingdoms? Or is their territory greater than your territory?' Three cities cited as object lessons: Calneh (Kullania in north Syria, conquered by Tiglath-Pileser III c. 738 BCE and likely already reduced when Amos spoke), Hamath the Great (the Syrian capital on the Orontes), and Gath of the Philistines (traditionally one of the five Philistine cities, destroyed by Uzziah according to 2 Chr 26:6). Whether these were conquered before Amos spoke (making them warnings) or after (a later gloss is possible) is debated. The rhetorical point is: are you more secure than they were?</p>",
    "3": "<p>'O you who put far away the day of disaster and bring near the seat of violence!' The syntax is inverted for emphasis: the elite who distance themselves psychologically from any thought of judgment ('the day of disaster is far off') are simultaneously 'bringing near the seat of violence' — their own unjust structures are creating the conditions for the judgment they deny. The 'seat of violence' (<em>shevet chamas</em>) means both a session/throne of violence (institutionalized oppression) and a plague/rod of violence (its punishment).</p>",
    "4": "<p>'Woe to those who lie on beds of ivory and stretch themselves out on their couches, and eat lambs from the flock and calves from the midst of the stall.' The 'beds of ivory' (<em>mitot shen</em>) are archaeologically confirmed: excavations at Samaria (conducted by Harvard in 1908-10 and Cambridge/British Institutions in 1931-35) uncovered hundreds of ivory plaques and inlays from 9th-8th century BCE contexts — furniture decoration with Phoenician and Egyptian motifs. Ahab's 'ivory house' is mentioned in 1 Kings 22:39. The lambs from the flock and stall-fed calves represent elite consumption: animals specifically fattened for banquets rather than ordinary flock animals.</p>",
    "5": "<p>'Who sing idle songs to the sound of the harp and like David improvise on musical instruments.' 'Like David' (<em>keDavid</em>) — the comparison is pointed: David played the harp as an act of worship (1 Sam 16:23, the soothing of Saul; 2 Sam 6:5, dancing before the ark; Ps titles). The elite of Samaria use David's instrument for self-entertainment. 'Improvise' (<em>parat</em>, literally: spread out, elaborate) suggests sophisticated musical composition — the artistic energy that should go to worship goes to private pleasure. The contrast between David's purposeful music and their idle songs indicts the misuse of cultural gifts.</p>",
    "6": "<p>'Who drink wine in bowls and anoint themselves with the finest oils, but are not grieved over the ruin of Joseph!' 'Wine in bowls' (<em>yishtu bemizrekey yayin</em>) — <em>mizrak</em> is the large cultic bowl used in temple ritual (Exod 27:3, Num 4:14); drinking wine in ceremonial bowls represents either shocking excess (using sacred vessels for parties) or simply oversized vessels. The anointing with 'the finest oils' (<em>shemen roshim</em>) is luxury personal care. The climax: 'not grieved over the ruin of Joseph' (<em>velo nechelu al-shever Yoseph</em>) — the northern kingdom was sometimes called 'Joseph' after the patriarch whose sons Ephraim and Manasseh constituted most of the northern territory.</p>",
    "7": "<p>'Therefore they shall now be the first of those who go into exile, and the revelry of those who stretch themselves out shall pass away.' The reversal: the 'first of the nations' (v1) become the first into exile. The verb 'go captive' (<em>yiglu</em>) was fulfilled literally: 2 Kings 17:6 records that Sargon II of Assyria carried the Israelites away to Halah, Habor, the river of Gozan, and the cities of the Medes. The 'revelry of those who stretch themselves out' (<em>mirzach seruchim</em>) — the <em>marzeah</em> was a known institution in the ancient Levant: a wealthy club or guild that held regular banquets, associated with both Baal worship and ancestral cults.</p>",
    "8": "<p>'The Lord GOD has sworn by himself, declares the LORD, the God of hosts: I abhor the pride of Jacob and hate his strongholds, and I will deliver up the city and all that is in it.' YHWH swearing by himself (<em>nishba adoaniy YHWH benafshoa</em>) — since there is no higher authority to invoke, God swears by his own being (cf. Gen 22:16, Heb 6:13-14). In the ancient world, oath-swearing by a deity's life was the strongest possible pledge. 'The pride of Jacob' (<em>ge'on Ya'aqov</em>) — the same phrase used in 8:7 as a divine title ('the LORD has sworn by the pride of Jacob') — here YHWH abhors what he is elsewhere. The distinction: divine pride is glory; human pride in Samaria is self-deception about their security.</p>",
    "9": "<p>'And if ten men remain in one house, they shall die.' The scene shifts abruptly to a future aftermath: pestilence (<em>deber</em>) so severe that a house with ten survivors still ends in death. The specific number ten suggests a family unit that survived the initial military disaster only to succumb to disease. Ancient Near Eastern warfare typically resulted in three waves of death: the battle itself, the subsequent famine as agriculture collapsed, and the plague that followed displacement and crowded conditions — exactly the pattern of Deut 28:21-22.</p>",
    "10": "<p>'And when one's relative, the one who anoints him for burial, shall take him up to bring the bones out of the house, and shall say to him who is in the innermost parts of the house, Is there still anyone with you? he shall say, No. Then he shall say, Silence! We must not mention the name of the LORD.' The specific cultural practice: a kinsman comes to retrieve bones for proper burial (secondary burial of bones was practiced in ancient Israel, especially in clay ossuaries from the Iron Age onward). 'We must not mention the name of the LORD' (<em>ki lo lehazkkir beshem YHWH</em>) — in the context of divine judgment, invoking YHWH's name might intensify the danger. This reflects a form of the OT teaching that YHWH's name is not to be invoked carelessly.</p>",
    "11": "<p>'For behold, the LORD commands, and the great house shall be struck down into fragments, and the little house into bits.' The 'great house' (<em>habayit hagadol</em>) and 'little house' (<em>habayit haqatan</em>) — both destroyed, with the distinction that the great house is struck into fragments (<em>rezazim</em>, cracked pieces) and the little house into bits (<em>baqiim</em>, splinters). The differentiation may reflect that the wealthy stone houses (like those found in the Samaria excavations, with their fine ashlar masonry) require more force to destroy than the ordinary mudbrick houses, but both will be leveled equally.</p>",
    "12": "<p>'Do horses run on rocks? Does one plow the sea with oxen? But you have turned justice into poison and the fruit of righteousness into wormwood.' The rhetorical questions establish natural impossibility: horses do not run on bare rock (they would break their legs); oxen do not plow the sea. Yet Israel has accomplished the morally equivalent impossibility: turning <em>mishpat</em> (justice, the system of covenant law) into poison (<em>rosh</em>, a bitter/poisonous plant, also gall) and the 'fruit of righteousness' (<em>peri tzedaqah</em>) into wormwood (<em>la'anah</em>). The covenant legal system designed to produce justice has been inverted into a mechanism of oppression.</p>",
    "13": "<p>'You who rejoice in Lo-debar, who say, Have we not by our own strength taken Karnaim for ourselves?' Lo-debar (<em>lo-davar</em>) literally means 'nothing/no-thing' — the place name is a pun. Karnaim means 'two horns' (the symbol of strength). Whether these are actual military victories of Jeroboam II's campaigns (cf. 2 Kings 14:25) or symbolic names is debated; most likely they were real towns in Transjordan captured during Israel's territorial expansion, but Amos uses the place names for their punning value: they rejoice in 'Nothing' and celebrate 'Horns' (military power) as if it were their own achievement.</p>",
    "14": "<p>'For behold, I will raise up against you a nation, O house of Israel, declares the LORD, the God of hosts; and they shall oppress you from Lebo-hamath to the Brook of the Arabah.' The 'nation' is Assyria — unnamed but identifiable in context. Lebo-hamath (the northern ideal border of Israel, Num 34:8, Ezek 47:15) to the Brook of the Arabah (the southern border, possibly the Wadi el-Hasa), representing the full territorial extent of Israel under Jeroboam II (2 Kings 14:25). The same territory that represented Israel's peak expansion will be the territory of Assyrian oppression — the blessing of territory becomes the curse of occupation.</p>"
  },
  "7": {
    "1": "<p>'This is what the Lord GOD showed me: behold, he was forming locusts when the latter growth was just beginning to sprout, and behold, it was the latter growth after the king's mowings.' The first of five visions (ch7:1-3, 7:4-6, 7:7-9, 8:1-3, 9:1). 'The latter growth after the king's mowings' (<em>hineh leqesh achar gizze hamelech</em>) refers to the agricultural practice: the first mowing of the spring crop went to the king as royal taxation (compare 1 Sam 8:15: 'he will take one-tenth of your grain'). The 'latter growth' (<em>leqesh</em>) was the smaller second crop that the farmer kept. YHWH forming locusts (<em>goze arbeh</em>) to destroy this second crop — the farmer's share after the king took his — would mean total ruin for ordinary people.</p>",
    "2": "<p>'When the locusts had finished eating the vegetation of the land, I said, O Lord GOD, please forgive! How can Jacob stand? He is so small!' Amos intercedes — perhaps unexpectedly for a prophet of judgment. 'How can Jacob stand? He is so small' (<em>mi yaqum Ya'aqov ki qaton hu</em>) — the argument from weakness, not from merit. This is similar to the Mosaic intercession pattern (Exod 32:11-14, Num 14:13-19) where the prophet argues not for Israel's righteousness but for divine mercy and YHWH's own purpose. 'Jacob' as the name for the nation — the patriarch who himself was small and dependent on divine provision.</p>",
    "3": "<p>'The LORD relented concerning this: It shall not be, said the LORD.' YHWH 'repented' (<em>nacham</em>) of this judgment — the same verb used in Gen 6:6-7 (YHWH regretting making humanity) and Exod 32:14 (YHWH relenting from destroying Israel after the golden calf). The theological paradox of prophetic intercession: the predetermined judgment is modified by prophetic prayer. The first two visions both end with divine relenting in response to intercession — establishing that Amos's intercession was effective. The third vision (7:7-9) notably does not include intercession and does not end with relenting.</p>",
    "4": "<p>'This is what the Lord GOD showed me: behold, the Lord GOD was calling for a judgment by fire, and it devoured the great deep and was eating up the land.' The second vision: fire of judgment devouring the 'great deep' (<em>tehom rabbah</em>) — the subterranean water source that feeds springs and wells (cf. Gen 7:11, 49:25). A fire that consumes the deep would dry up all underground water, creating comprehensive drought. The vision escalates from locusts (destroying the harvest) to fire (destroying the water supply itself), building the case that YHWH has multiple instruments of comprehensive judgment available.</p>",
    "5": "<p>'Then I said, O Lord GOD, please cease! How can Jacob stand? He is so small!' The second intercession uses the same form as the first — the repetition is liturgically deliberate, like a pattern of prayer. The parallel structure (vision → divine action → prophetic intercession → divine relenting) establishes Amos's intercessory role. Unlike the writing prophets who are often presented primarily as proclaimers of judgment, Amos here shows the intercessory dimension — standing between YHWH and the people to plead, as Moses did (Exod 32:11, Deut 9:18-20).</p>",
    "6": "<p>'The LORD relented concerning this: This also shall not be, said the Lord GOD.' The second relenting follows the same pattern. 'This also shall not be' — the emphatic 'also' marks the continuation of the intercessory success. But the three-part structure (locusts, fire, plumb line) follows the pattern of warning escalation: the first two warnings are rescinded; the third is definitive. This narrative structure teaches that prophetic intercession is effective but not unlimited — there is a point of no return that the third vision reaches.</p>",
    "7": "<p>'This is what he showed me: behold, the Lord was standing beside a wall built with a plumb line, with a plumb line in his hand.' The plumb line (<em>anakh</em>) is a weight on a string used by builders to verify that a wall is perfectly vertical — a standard construction tool in the ancient world. Stone walls built without a plumb line are vulnerable to collapse; a wall 'made with a plumb line' is one that was built correctly. YHWH standing beside such a wall with a plumb line is the image of a building inspector about to test whether the structure meets its original specification — i.e., whether Israel meets the covenant standard.</p>",
    "8": "<p>'And the LORD said to me, Amos, what do you see? And I said, A plumb line. Then the Lord said, Behold, I am setting a plumb line in the midst of my people Israel; I will never again pass by them.' The direct dialogue between YHWH and prophet is characteristic of the vision reports. 'I will never again pass by them' (<em>lo osif od avor lo</em>) — the decisive break from the first two visions: no more relenting, no more passing over judgment. The phrase 'pass by' (<em>avor</em>) may echo the Passover/Exodus language (YHWH 'passing by' to judge Egypt, Exod 12:12-13) — now inverted: YHWH will not pass by Israel without judgment.</p>",
    "9": "<p>'And the high places of Isaac shall be made desolate, and the sanctuaries of Israel shall be laid waste, and I will rise against the house of Jeroboam with the sword.' 'High places of Isaac' (<em>bamot Yitzchaq</em>) — the local worship sites associated with the patriarchal tradition (cf. Gen 26:24-25: Isaac building an altar at Beersheba). 'Sanctuaries of Israel' (<em>miqdeshei Yisrael</em>) — the royal cult centers including Bethel and Dan. The specific mention of Jeroboam's house: the word of YHWH through Amos against Jeroboam II reaches the ears of Amaziah the priest (v10), who reports it as sedition. This was not mere religious controversy but a political threat claim.</p>",
    "10": "<p>'Then Amaziah the priest of Bethel sent to Jeroboam king of Israel, saying, Amos has conspired against you in the midst of the house of Israel. The land is not able to bear all his words.' The Amaziah confrontation is the only extended narrative in Amos. Amaziah was the 'priest of Bethel' (<em>kohen Bet-El</em>) — the head of the royal cult center established by Jeroboam I (1 Kings 12:29-33). His report to King Jeroboam II frames Amos's prophecy as political conspiracy (<em>qesher</em>) — the term used for treasonous palace coups (2 Kings 15:10-15). In the ANE, a prophet who predicted the death of a king was legally dangerous — Jer 26:11 shows Jeremiah later facing death for similar prophecies.</p>",
    "11": "<p>'For thus Amos has said, Jeroboam shall die by the sword, and Israel must go into exile away from his land.' Amaziah paraphrases Amos's message accurately (cf. 7:9), and the political charge is clear: predicting the king's violent death was tantamount to planning it in ancient Near Eastern legal thinking. Kings routinely consulted prophets for legitimation; a prophet who predicted their downfall was functionally an enemy of the state. The historical record: Jeroboam II did not die by the sword (2 Kings 14:29 records he 'slept with his fathers'), though his son Zechariah was assassinated after only six months (2 Kings 15:10).</p>",
    "12": "<p>'And Amaziah said to Amos, O seer, go, flee away to the land of Judah, and eat bread there, and prophesy there.' 'Seer' (<em>chozeh</em>) rather than 'prophet' (<em>nabhi</em>) — the distinction may be dismissive or technical. Amaziah's command to 'eat bread' in Judah is a reference to prophetic income: professional prophets received payment (cf. 1 Sam 9:7-8: paying Saul a fee before consulting Samuel). Amaziah assumes Amos is a professional prophet who has come to Bethel for income and can be sent back to his own territory. This misunderstanding provides the occasion for Amos's most famous self-identification.</p>",
    "13": "<p>'But never again prophesy at Bethel, for it is the king's sanctuary, and it is a temple of the kingdom.' 'The king's sanctuary' (<em>miqdash-melek</em>) and 'temple of the kingdom' (<em>beit mamlakhah</em>) — Amaziah reveals Bethel's actual status: it is a royal chapel, not an independent religious institution. The Bethel sanctuary was founded specifically to prevent the northern kingdom's subjects from going to Jerusalem (1 Kings 12:27-28); it was architecturally and institutionally linked to royal power. Amaziah's authority to expel Amos derives from the sanctuary's royal patronage, not from religious principle.</p>",
    "14": "<p>'Then Amos answered and said to Amaziah, I was no prophet, nor a prophet's son, but I was a herdsman and a dresser of sycamore figs.' One of the most analyzed statements in prophetic literature. 'I was no prophet' (<em>lo nabhi anochi</em>) — the form could be past tense (I was not a prophet before my calling) or present (I am not a prophet in the professional sense). 'A prophet's son' (<em>ben-nabhi</em>) refers to the prophetic guilds (benei hanevi'im) — schools of prophets associated with Samuel (1 Sam 10:10), Elijah (2 Kings 2:3), and Elisha (2 Kings 4:38). A <em>noqed</em> (herdsman/sheep-breeder) — the same term used of Mesha king of Moab in 2 Kings 3:4. Sycamore fig-dresser (<em>boles shiqmim</em>) — sycamore figs require a specific treatment (pricking or scoring) to ripen properly.</p>",
    "15": "<p>'But the LORD took me from following the flock, and the LORD said to me, Go, prophesy to my people Israel.' The direct divine call without mediation — 'the LORD took me' (<em>wayyiqacheni YHWH</em>) from the flock. This parallels David called from shepherding (2 Sam 7:8: 'I took you from the pasture, from following the sheep'), Moses called from shepherding (Exod 3:1-4), and the general OT pattern of divine call as social disruption. The call is non-institutional: no prophetic school, no mentor-figure, no royal appointment. The prophetic authority derives entirely from the divine commission, not from institutional standing.</p>",
    "16": "<p>'Now therefore hear the word of the LORD. You say, Do not prophesy against Israel, and do not preach against the house of Isaac.' Amaziah's prohibition ('do not prophesy against Israel') is turned back on Amaziah himself — he is now the subject of a personal oracle. The phrase 'the house of Isaac' (<em>beit Yitzchaq</em>) echoes the 'high places of Isaac' (7:9), using the patriarchal name for the northern kingdom. The authority claimed by Amaziah to silence prophetic speech is itself the subject of prophetic judgment: the silencer of the word will hear the word pronounced against him personally.</p>",
    "17": "<p>'Therefore thus says the LORD: Your wife shall be a prostitute in the city, and your sons and daughters shall fall by the sword, and your land shall be divided up with a measuring line; you yourself shall die in an unclean land, and Israel shall surely go into exile away from its land.' The oracle against Amaziah is comprehensive: his wife, children, land, and his own death in a foreign (unclean) land. 'A prostitute in the city' — the seizure of a defeated city's women as spoils (cf. Isa 13:16, Zech 14:2). 'Your land shall be divided with a measuring line' — the Assyrian practice of redistributing conquered territory to settlers. 'Die in an unclean land' — dying outside the covenant land meant burial without covenant community, a profound curse.</p>"
  },
  "8": {
    "1": "<p>'This is what the Lord GOD showed me: behold, a basket of summer fruit.' The fourth vision uses a wordplay that requires knowing Hebrew. A basket of <em>qayitz</em> (summer fruit — figs, grapes, pomegranates at their ripest). The pun in v2: YHWH says 'the <em>qetz</em> (end) has come upon my people Israel.' The summer fruit is ripe — fully mature, at its peak — and so is Israel's judgment: ready for harvest. The summer fruit (<em>qayitz</em>) was gathered at the end of the agricultural year; the <em>qetz</em> (end) is the end of Israel's national existence. The vision is an acted parable of completed ripeness.</p>",
    "2": "<p>'He said, Amos, what do you see? And I said, A basket of summer fruit. Then the LORD said to me, The end has come upon my people Israel; I will never again pass by them.' The wordplay <em>qayitz/qetz</em> establishes that the summer harvest is a sign of the approaching end. 'I will never again pass by them' repeats 7:8 — definitively: the period of intercession and relenting is over. The phrase recurs a second time (from 7:8) to emphasize the finality. In 7:8 it followed the plumb line vision; here it follows the summer fruit, confirming the trajectory of the last two visions toward irreversible judgment.</p>",
    "3": "<p>'The songs of the temple shall become wailings in that day, declares the Lord GOD. So many dead bodies! They are thrown everywhere. Silence!' 'Songs of the temple' (<em>shirot heikal</em>) — the sacred songs of the Bethel sanctuary (which had professional musicians and elaborate worship, cf. 5:23) become funeral wailings. 'In every place they are thrown' (<em>bekhol-maqom hishlich</em>) — the random casting of unburied bodies everywhere, the sign of total defeat and the activation of the covenant curse (Deut 28:25-26: 'your dead bodies shall be food for all birds of the air'). 'Silence!' (<em>has</em>) — the command to silence in the face of overwhelming death.</p>",
    "4": "<p>'Hear this, you who trample on the needy and bring the poor of the land to an end.' The economic oracle that follows the vision — the specific social crime that makes Israel ripe for judgment. 'Trample on the needy' (<em>hashoa'afim ebyon</em>) and 'bring the poor to an end' (<em>lashbit aniyei-aretz</em>) — both verbs are strong: trampling/panting after the poor, and actively eliminating the poor class (by absorbing their land, driving them into debt slavery). This directly indicts the landholding elite of Jeroboam II's prosperous kingdom.</p>",
    "5": "<p>'Saying, When will the new moon be over, that we may sell grain? And the Sabbath, that we may offer wheat for sale, that we may make the ephah small and the shekel great and deal deceitfully with false balances.' The religious calendar — new moon (<em>rosh chodesh</em>) and Sabbath (<em>shabbat</em>) — were both days of commercial rest (cf. 2 Kings 4:23: 'Why will you go to him today? It is neither new moon nor sabbath'). The merchants observe the form (they cease trading on holy days) while their hearts are on the resumption of fraud. The double fraud: a small ephah (short measure for the buyer) and a large shekel (overweight payment demand from the seller) simultaneously extracted maximum profit from every transaction.</p>",
    "6": "<p>'That we may buy the poor for silver and the needy for a pair of sandals and sell the trash of the wheat?' Three practices condemned: (1) buying the poor as slaves for debt (silver), (2) buying the needy for a pair of sandals (either a pun on legal custom — sandal exchange in property transfer, Ruth 4:7 — or meaning they will enslave someone for a trivial debt), (3) selling the refuse of the wheat (<em>maphel bar</em>) — the chaff, husks, and dirt swept up from the threshing floor, mixed with grain and sold as if it were pure wheat. The three practices together represent systematic fraud targeting the vulnerable.</p>",
    "7": "<p>'The LORD has sworn by the pride of Jacob: Surely I will never forget any of their deeds.' 'The pride of Jacob' (<em>ge'on Ya'aqov</em>) — used in 6:8 for what YHWH abhors in Israel's self-regard; here it is a divine oath title (YHWH's own pride/majesty). The paradox is that the same term applies both to the condemned pride of Israel's elite and to the divine glory that is the basis of the oath. 'I will never forget any of their deeds' — the divine memory as guarantee of judgment. In Deut 32:34 YHWH says their punishment is 'sealed up in my treasuries'; here the explicit promise is that economic oppression will not be forgotten.</p>",
    "8": "<p>'Shall not the land tremble on this account, and everyone mourn who dwells in it, and all of it rise like the Nile, and be tossed about and sink again, like the Nile of Egypt?' The land mourning (<em>avela ha-aretz</em>) — the covenant land responding physically to moral catastrophe, as in Hos 4:3 and Joel 1:10. The Nile flood metaphor (<em>ke'or Mitzrayim</em>) — the Nile's seasonal flooding, which rises dramatically and then falls, is used as an image of land upheaval. The Nile's flood was both the source of Egyptian agricultural abundance and a powerful natural force; its application to the land of Israel suggests a catastrophic inundation of the covenant land.</p>",
    "9": "<p>'And on that day, declares the Lord GOD, I will make the sun go down at noon and darken the earth in broad daylight.' 'The sun going down at noon' (<em>vehevati hashemesh batzoharayim</em>) — darkness at noon is the image of total disorientation; noon is the height of light, not the time for darkness. Whether this refers to a solar eclipse (a solar eclipse was visible in Assyria in 763 BCE and may have been seen in the Levant) or is purely metaphorical is debated. The image recurs in Joel 2:10, 3:15 and becomes the sign of the Day of YHWH. Mark 15:33 records darkness from noon to three at the crucifixion — an event the NT reads against this background.</p>",
    "10": "<p>'I will turn your feasts into mourning and all your songs into lamentation; I will bring sackcloth on every waist and baldness on every head; I will make it like the mourning for an only son and the end of it like a bitter day.' The festival-to-mourning reversal: the three pilgrimage feasts (<em>chagim</em>) and their songs become funeral rites. 'Baldness on every head' (<em>qorchah al-kol-rosh</em>) was a mourning practice (Isa 22:12, Jer 16:6, Mic 1:16) — shaving the head as a sign of grief. 'Mourning for an only son' (<em>evel yachid</em>) — the most extreme grief, the death of the sole heir, the end of the family line. Jer 6:26 and Zech 12:10 use the same image.</p>",
    "11": "<p>'Behold, the days are coming, declares the Lord GOD, when I will send a famine on the land — not a famine of bread, nor a thirst for water, but of hearing the words of the LORD.' The famine of the word (<em>ra'av lishmo'a et divrei YHWH</em>) — one of Amos's most distinctive and influential oracles. Having rejected the prophetic word, Israel will find itself in a situation where they desperately seek it and cannot find it. The word of YHWH, freely available and constantly refused, will be removed. The relationship between prophetic rejection and prophetic silence is explicit: 'they would not listen' (2:12, 7:12-13) leads to 'they shall seek the word of the LORD and not find it.'</p>",
    "12": "<p>'They shall wander from sea to sea, and from north to east; they shall run to and fro, to seek the word of the LORD, but they shall not find it.' The frantic, undirected search — 'from sea to sea' (<em>miyam ad-yam</em>) and 'from north to east' (rather than the expected north to south) suggesting disorientation. The Diaspora context: the northern Israelites scattered among the nations would indeed find themselves in places where access to prophetic revelation and covenant worship was impossible. The 'seeking and not finding' of the word echoes Prov 1:28 (the fool seeks wisdom after rejecting it, but wisdom turns away) — applied here nationally.</p>",
    "13": "<p>'In that day the lovely virgins and the young men shall faint for thirst.' The most vigorous members of the population — 'lovely virgins' (<em>betulot tovot</em>) and young men (<em>bahurim</em>) — fainting from thirst. Both groups represent the prime of Israel's demographic future: if they collapse, the nation has no next generation. The thirst is presumably both literal (the drought that follows agricultural collapse) and metaphorical (the absence of the word in v11-12). The specific mention of these two groups echoes Joel 1:8 (the virgin lamenting), connecting the locust-plague imagery of Joel with Amos's judgment oracle.</p>",
    "14": "<p>'Those who swear by the Guilt of Samaria, and say, As your god lives, O Dan, and, As the Way of Beersheba lives — they shall fall and never rise again.' 'The Guilt of Samaria' (<em>ashmat Shomron</em>) — possibly the golden calf of Bethel (near Samaria) called 'guilt/sin' (<em>asham</em>) as a polemical repointing; alternatively 'Ashima,' a deity of Hamath (2 Kings 17:30). 'As your god lives, O Dan' — the golden calf at Dan (1 Kings 12:29), invoked in oath-formulas. 'The Way of Beersheba' (<em>derekh Be'er-Sheva</em>) — the pilgrimage route to the ancient patriarchal site in the south. All three are dismissed together as false cult objects; those who swear by them will fall irreversibly.</p>"
  },
  "9": {
    "1": "<p>'I saw the Lord standing beside the altar, and he said: Strike the capitals until the thresholds shake, and shatter them on the heads of all the people; and those who are left of them I will kill with the sword; not one of them shall flee away; not one of them shall escape.' The fifth and final vision — no longer an object or image but YHWH himself standing beside the altar. The altar is almost certainly Bethel's royal altar, the cult center condemned throughout Amos. The command to 'strike the capitals' (<em>hak hakaphtor</em>) — the capital-stones atop the pillars — so that the thresholds shake and the whole structure collapses onto the people is a judgment both on the building and on those inside. The vision echoes Samson's destruction of the Philistine temple (Judg 16:29-30).</p>",
    "2": "<p>'If they dig into Sheol, from there shall my hand take them; if they climb up to heaven, from there I will bring them down.' The comprehensive divine omnipresence in judgment — a stark contrast to Ps 139:8 (the same concept applied to divine care: 'if I make my bed in Sheol, you are there'). Here the omnipresence that in Ps 139 is comforting becomes terrifying: there is no place to flee. 'Dig into Sheol' (<em>yachteru bish'ol</em>) — the underworld as the place furthest from divine presence (Ps 88:5-6); 'climb up to heaven' (<em>ya'alu hashamayim</em>) — the highest conceivable place. Both are equally accessible to YHWH's judgment hand.</p>",
    "3": "<p>'If they hide themselves on the top of Carmel, from there I will search them out and take them; and if they hide from my sight at the bottom of the sea, there I will command the serpent, and it shall bite them.' Carmel (the forested mountain range on the Mediterranean coast, famous for its dense cover, cf. Jer 46:18, Mic 7:14) — the ideal hiding place, inaccessible and heavily wooded. 'The bottom of the sea' — where the sea-serpent (<em>nachash</em>) or Leviathan dwells (cf. Job 41, Ps 74:13-14). The cosmic servant — even the chaos-serpent of the deep is commanded by YHWH to execute judgment. No created power, not even the monster of the deep, is outside YHWH's command.</p>",
    "4": "<p>'And if they go into captivity before their enemies, there I will command the sword, and it shall kill them; and I will fix my eyes on them for evil and not for good.' Even in captivity — the final state of the defeated — there is no safety from the sword. 'I will fix my eyes on them for evil and not for good' (<em>samti eynai alehem lera'ah velo letovah</em>) — the divine gaze that in Ps 34:15 ('the eyes of the LORD are on the righteous') is protective becomes judicial. The inversion of covenant blessing into covenant curse: YHWH 'fixing his eyes' was the promise of protection (Num 6:25-26: the Aaronic blessing); here it becomes the promise of inescapable judgment.</p>",
    "5": "<p>'The Lord GOD of hosts, he who touches the earth and it melts, and all who dwell in it mourn, and all of it rises like the Nile, and sinks again, like the Nile of Egypt.' The third doxology of Amos (the first at 4:13, the second at 5:8-9, the third at 9:5-6). The doxologies are probably liturgical hymn fragments incorporated into the book at structural transition points. 'Touches the earth and it melts' (<em>hanogeha la-aretz vatamog</em>) — divine touch as cosmological power (cf. Ps 104:32: 'who looks on the earth and it trembles'). The Nile-flood image (also in 8:8) unifies the doxology with the surrounding judgment oracles.</p>",
    "6": "<p>'who builds his upper chambers in the heavens and founds his vault upon the earth; who calls for the waters of the sea and pours them out upon the surface of the earth — the LORD is his name.' The cosmic architecture of YHWH's dwelling: 'upper chambers in the heavens' (<em>aliyotav bashamayim yivneh</em>) — the heavenly palace-chambers above the sky-vault; 'vault upon the earth' (<em>aguddato al-aretz yesadah</em>) — the dome-vault of heaven founded on the earth (cf. Gen 1:6-7, the <em>raqia</em>/firmament). 'Calls for the waters of the sea and pours them out upon the earth' — the power over rain and flood (cf. Job 38:8-11, 34-38). The divine name '<em>YHWH shemo</em>' closes the doxology, grounding all cosmic power in the covenant name.</p>",
    "7": "<p>'Are you not like the Cushites to me, O people of Israel? declares the LORD. Did I not bring up Israel from the land of Egypt, and the Philistines from Caphtor and the Syrians from Kir?' The most universalistic statement in Amos — and one of the most startling in the OT. Cushites (Ethiopians/Nubians) were geographically the most distant people Israel knew; YHWH treats Israel no differently than them. The Philistines from Caphtor (Crete — confirmed by Deut 2:23, Jer 47:4, and Egyptian texts referring to the Sea Peoples' Aegean origins) and the Syrians from Kir (location debated; possibly Mesopotamia, cf. 2 Kings 16:9 where Tiglath-Pileser deports Syrians to Kir): YHWH governed the migrations of all peoples. Israel's Exodus was not a unique privilege but one instance of divine governance of nations.</p>",
    "8": "<p>'Behold, the eyes of the Lord GOD are upon the sinful kingdom, and I will destroy it from the surface of the ground, except that I will not utterly destroy the house of Jacob, declares the LORD.' The 'sinful kingdom' (<em>mamlakhah hachattaah</em>) — the Northern Kingdom as an entity defined by its foundational sin (Jeroboam I's calves). The total destruction with the exception clause: 'I will not utterly destroy (<em>lo hashmed ashmed</em>, destroy absolutely) the house of Jacob.' The phrase uses the infinitive absolute for intensification of the verb, then negates it — even in absolute judgment there is a divine limit. The 'house of Jacob' survives even when the 'sinful kingdom' does not.</p>",
    "9": "<p>'For behold, I will command, and shake the house of Israel among all the nations as one shakes with a sieve, but no kernel shall fall to the earth.' The sieve (<em>kevar</em>) as an image of divine judgment and preservation simultaneously. The sieve was used in grain processing: shaking separates grain from chaff and debris. YHWH shaking Israel among the nations — the sifting scatters everything; yet 'no kernel shall fall to the earth' (<em>velo-yipol tzaror aretz</em>). The good grain (the faithful remnant) is preserved in the sieve; the sinners ('those who say evil shall not overtake us,' v10) perish. The sieve image combines comprehensive judgment (no nation is exempted from the shaking) with selective preservation.</p>",
    "10": "<p>'All the sinners of my people shall die by the sword, who say, Disaster shall not overtake or meet us.' The 'sinners' (<em>chatta'e ammi</em>) — specifically identified as those who say 'disaster shall not overtake us' (<em>lo-tagish velo takdim badenu hara'ah</em>), the complacent deniers of prophetic warning (cf. 6:3: 'you who put far away the day of disaster'). The specific identification of the condemned is with the attitude of denial, not merely with specific acts. The willful rejection of the prophetic warning — 'evil shall not come near or reach us' — is the defining mark of those who fall while the remnant is preserved.</p>",
    "11": "<p>'In that day I will raise up the booth of David that is fallen and repair its breaches, and raise up its ruins and rebuild it as in the days of old.' The Davidic restoration oracle — one of the most significant in the Minor Prophets. 'The booth of David' (<em>sukkat David</em>) — not the Solomonic temple or the permanent palace but the <em>sukkah</em>, the temporary shelter. The image may refer to the Davidic dynasty in its weakened post-division state (by Amos's time, the Davidic line ruled only Judah, much reduced from David's empire); or to the tent over the ark that David erected (2 Sam 6:17); or more broadly to the Davidic covenant. James quotes this in Acts 15:16-17 as justification for Gentile inclusion in the people of God — the restored 'booth of David' encompasses 'all the nations who are called by my name.'</p>",
    "12": "<p>'That they may possess the remnant of Edom and all the nations who are called by my name, declares the LORD who does this.' 'Possess the remnant of Edom' — Edom as the representative hostile nation (descended from Esau, perpetual rival of Jacob). The phrase 'all the nations who are called by my name' (<em>kol-hagoyim asher-niqra shemi alehem</em>) becomes the key text in Acts 15:17 for the mission to Gentiles: James argues that the incorporation of Gentile believers into the community of faith fulfills this Amos oracle. The Septuagint version of this verse (cited in Acts 15) reads 'all the nations over whom my name has been called' — the possession of Edom and nations reflects eschatological sovereignty.</p>",
    "13": "<p>'Behold, the days are coming, declares the LORD, when the plowman shall overtake the reaper and the treader of grapes him who sows the seed; the mountains shall drip sweet wine, and all the hills shall flow with it.' The eschatological agricultural abundance: the harvest is so great that the plowman (preparing for next year's sowing) catches up with the reaper (still harvesting this year's crop). The perpetual harvest — time collapsed to simultaneity, one season running into the next. Mountains dripping wine and hills flowing with it — the hyperbole of superabundance (cf. Joel 3:18, Isa 35:1-2). This is the reversal of the agricultural deprivation in chs4-8 (held back rain, blight, mildew) — the covenant curse overturned by covenant restoration.</p>",
    "14": "<p>'I will restore the fortunes of my people Israel, and they shall rebuild the ruined cities and inhabit them; they shall plant vineyards and drink their wine, and they shall make gardens and eat their fruit.' 'Restore the fortunes' (<em>shavti et-shevut</em>) — the standard covenant-restoration formula (also in Joel 3:1, Jer 29:14, 30:3, Deut 30:3). The rebuilding of ruined cities, planting of vineyards, making of gardens — these are precisely the activities disrupted by warfare and deportation. The promise is not merely of spiritual restoration but of concrete material re-establishment: the physical infrastructure of life in the covenant land. The Amos oracles of social justice find their resolution not in the perpetuation of the current corrupt order but in its complete replacement.</p>",
    "15": "<p>'I will plant them on their land, and they shall never again be uprooted out of the land that I have given them, says the LORD your God.' The closing promise: 'I will plant them' (<em>netattim al-admatam</em>) — the image of Israel as a vine/tree planted in the covenant soil (cf. Ps 80:8-9, Isa 5:1-7). 'Never again be uprooted' (<em>velo yinnateishu od</em>) — the permanent reversal of exile; the opposite of 9:8 where the sinful kingdom is destroyed 'from the surface of the ground.' The final word of Amos is not judgment but the divine land-gift: 'the land that I have given them, says the LORD your God.' The covenant relationship (<em>YHWH Eloheikhem</em>) is restored and the land-gift is permanent.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'amos')
    merge_comm(c, DATA)
    save_comm('mkt-context', 'amos', c)
    total = sum(len(v) for v in DATA.values())
    print(f'amos mkt-context: added up to {total} verses across ch6-9')

if __name__ == '__main__':
    main()
